// // This module compares two 2-bit numbers and outputs whether the first number is less than, equal to, or greater than the second number.
module comparator (
  input [1:0] a,
  input [1:0] b,
  output a_gt_b,
  output a_eq_b,
  output a_lt_b
);

  assign a_gt_b = (a > b);
  assign a_eq_b = (a == b);
  assign a_lt_b = (a < b);

endmodule
